import { isPointThreshold } from '../../../types/type-guards.js';
import { MARKER_RADIUS } from '../markers/constants.js';
import type { ThresholdMarker } from '../types.js';

function getPixelBoundary(
  threshold: ThresholdMarker,
  type: 'min' | 'max',
): number {
  const { y0, y1 } = threshold;

  if (isPointThreshold(y0, y1)) {
    return type === 'min' ? y0 - MARKER_RADIUS : y0 + MARKER_RADIUS;
  }

  return type === 'min' ? Math.min(y0, y1) : Math.max(y0, y1);
}

export function groupOverlappingMarkers(
  markers: ThresholdMarker[],
): ThresholdMarker[][] {
  const groups: ThresholdMarker[][] = [];
  const sortedByMin = [...markers].sort(
    (markerA, markerB) =>
      Math.min(markerA.y0, markerA.y1) - Math.min(markerB.y0, markerB.y1) ||
      Math.max(markerA.y0, markerA.y1) - Math.max(markerB.y0, markerB.y1),
  );

  for (const current of sortedByMin) {
    const currentMin = getPixelBoundary(current, 'min');

    const groupIndex = groups.findIndex((group) =>
      group.some((value) => {
        const valueMax = getPixelBoundary(value, 'max');

        return currentMin < valueMax;
      }),
    );

    if (groupIndex !== -1) {
      groups[groupIndex].push(current);
    } else {
      groups.push([current]);
    }
  }

  return groups;
}
